urlset:

  {{ site.url }}/
  daily
  1.0

{% for page in pages %}
{% if page != 'index' and page != '404' %}

  {{ site.url }}/{{ page }}.html
  monthly
  0.5

{% endif %}
{% endfor %}
{% for cat_slug in categories.keys() %}

  {{ site.url }}/{{ cat_slug | lower | replace(' ', '-') }}/
  weekly
  0.8

{% endfor %}
{% for article in articles %}

  {{ site.url }}/{{ article.slug }}/
  {{ article.date }}
  weekly
  0.7

{% endfor %}
